  ('cpa-moex-00041', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關會計師職業道德規範之敘述，何者正確？', '["會計師間不得相互介紹業務", "事務所中僅會計師必須遵循會計師職業道德規範", "會計師事務所設立分事務所，應由會計師親自主持", "會計師不得作任何宣傳或廣告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00042', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關審計準則265號「內部控制缺失之溝通」之規定，下列敘述何者錯誤？', '["該準則所稱查核人員須與受查者溝通之內部控制缺失，僅限於就查核財務報表時所辨認之 內部控制缺失", "查核人員一定要以書面方式，與管理階層及治理單位溝通內部控制顯著缺失", "內部控制缺失是否顯著，取決於不實表達是否已實際發生及實際發生之潛在影響", "管理階層或治理單位如要求查核人員出具敘明其於查核過程中，未辨認出內部控制顯著缺 失之書面溝通，查核人員得出具該書面溝通"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00043', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '在規劃查核時，查核人員所考量之查核風險，下列敘述何者正確？', '["當財務報表存有重大不實表達時，查核人員無法適當修正其意見的風險", "受查者設置內部稽核人員，無法查出其帳戶餘額易遭受重大不實表達的風險", "與受查者的前任會計師聯繫，瞭解前任會計師未能辨認財務報表潛在重大之錯誤風險", "受查者設有內部控制制度，而仍無法偵出重大不實表達的風險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00044', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依據審計準則210號「查核案件條款之協議」，下列何項條款為必須記載於查核委任書或其他 適當形式之書面協議？', '["會計師賠償責任之限制", "酬金之確定金額及收款方式", "會計師查核財務報表之責任", "提供查核工作底稿予第三方之義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00045', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關查核規劃作業之性質及範圍，下列何項非主要考量之因素？', '["查核團隊主要成員對受查者之查核經驗", "查核期間有關情況之改變", "查核公費的高低", "受查者之規模與複雜度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
